import React from 'react';
import {
  AllocationVarianceConfirmModal,
  SalesVoucherFormShell,
  VoucherFormBodySkeleton,
  VoucherFormFooterSkeleton,
  VoucherFormStatusGroup,
  VoucherFormToolbar,
  VoucherMoneyFooter,
} from '../../../components/voucher';
import { HoaDonHeaderSection } from '../../../components/bh/HoaDonHeaderSection';
import { InvoiceLinesGrid, useMaterialLinesSelection } from '../../../components/form';
import { HeaderDiscountClearConfirmModal, UnsavedChangesModal } from '../../../components/form';
import { useHoaDonFormPage } from '../../../hooks/useHoaDonFormPage';
import { formatProcessingLevelFromOptions } from '../../../utils/voucherProcessingLevelOptions';
import { emptyInvoiceLine } from '../../../utils/orderLines';
import df from '../../../styles/documentForm.module.css';

const HoaDonFormPage: React.FC = () => {
  const vm = useHoaDonFormPage();
  const { copyLine, lineRowProps, setSelectedLineIndex } = useMaterialLinesSelection(vm.lines, vm.setLines);

  const addLine = () => {
    vm.setLines(prev => [...prev, emptyInvoiceLine()]);
    setSelectedLineIndex(vm.lines.length);
  };

  const removeLine = (idx: number) => {
    vm.setLines(prev => {
      const next = prev.filter((_, i) => i !== idx);
      return next.length ? next : [emptyInvoiceLine()];
    });
    setSelectedLineIndex(Math.max(0, idx - 1));
  };

  const processingLevelLabel = formatProcessingLevelFromOptions(
    vm.processingLevel,
    vm.processingLevelOptions,
  );

  const toolbar = (
    <div className={df.stickyTop}>
      <VoucherFormToolbar
        testIdPrefix={vm.TEST_ID}
        insetShell
        title={vm.isNew ? 'Tạo hóa đơn' : `Hóa đơn — ${vm.invoiceCode || '...'}`}
        processingLevelBadge={
          !vm.isNew ? <VoucherFormStatusGroup processingLevelLabel={processingLevelLabel} /> : undefined
        }
        formMode={vm.toolbarMode}
        showViewHint={vm.isViewMode && vm.showEditDelete}
        showApproveButton={false}
        canApprove={false}
        showPostButton={false}
        canPost={false}
        canCopy={false}
        canPrint={false}
        canHistory={false}
        showEditButton={vm.showEditDelete}
        showDeleteButton={vm.showEditDelete}
        showNewButton={vm.canCreate}
        canEdit={vm.showEditDelete}
        canDelete={vm.showEditDelete}
        canSave={vm.isNew ? vm.canCreate : vm.canUpdate}
        saving={vm.saving}
        saveLabel="Tạo hóa đơn"
        onBack={vm.handleBack}
        onApprove={() => {}}
        onPost={() => {}}
        onCopy={() => {}}
        onPrint={() => {}}
        onSearch={() => {}}
        onNew={() => vm.navigate('/bh/hoa-don/them')}
        onEdit={vm.handleEdit}
        onSave={vm.handleSave}
        onCancel={vm.handleCancel}
        onDelete={vm.handleDelete}
        disabledReasons={{
          edit: vm.isStatusLocked ? 'Chỉ xem — hóa đơn đã ghi sổ hoặc đã phát hành' : undefined,
          delete: vm.isStatusLocked ? 'Không thể xóa hóa đơn đã ghi sổ' : undefined,
        }}
      />
      {vm.isViewMode && vm.isStatusLocked ? (
        <div className={df.readOnlyHint} data-testid={`${vm.TEST_ID}-view-lock-hint`}>
          <i className="fas fa-lock" /> Chỉ xem — hóa đơn không ở trạng thái Nháp
        </div>
      ) : null}
    </div>
  );

  if (vm.loading) {
    return (
      <SalesVoucherFormShell
        testIdPrefix={vm.TEST_ID}
        header={toolbar}
        footer={<VoucherFormFooterSkeleton testIdPrefix={vm.TEST_ID} />}
      >
        <VoucherFormBodySkeleton testIdPrefix={vm.TEST_ID} />
      </SalesVoucherFormShell>
    );
  }

  return (
    <>
      <SalesVoucherFormShell
        testIdPrefix={vm.TEST_ID}
        header={toolbar}
        footer={(
          <VoucherMoneyFooter
            testIdPrefix={vm.TEST_ID}
            rows={[
              { id: 'productTotal', label: 'Tổng tiền:', amount: vm.totals.productTotal },
              { id: 'tax', label: 'Thuế:', amount: vm.totals.taxAmount },
              { id: 'netTotal', label: 'Thành tiền:', amount: vm.totals.total, emphasize: true },
            ]}
            discount={{
              displayAmount: vm.discountDisplayTotal,
              headerDiscountAmount: vm.headerDiscountAmount,
              useHeaderDiscount: vm.useHeaderDiscount,
              onUseHeaderDiscountChange: vm.setUseHeaderDiscount,
              onHeaderDiscountAmountChange: vm.setHeaderDiscountAmount,
              allocation: vm.headerDiscountAllocation,
              onAllocationChange: vm.setHeaderDiscountAllocation,
              hasLineDiscount: vm.lineDiscountActive,
              readOnly: !vm.canEditLines,
            }}
            variance={{
              amount: vm.varianceAmount,
              onAmountChange: vm.setVarianceAmount,
              readOnly: !vm.canEditLines,
            }}
            processingLevel={vm.processingLevel}
            onProcessingLevelChange={vm.setProcessingLevel}
            processingLevelOptions={vm.processingLevelOptions}
            processingLevelDisabled={vm.fieldLock.selectDisabled}
          />
        )}
      >
        <HoaDonHeaderSection
          testIdPrefix={vm.TEST_ID}
          headerExpanded={vm.headerExpanded}
          setHeaderExpanded={vm.setHeaderExpanded}
          fieldLock={vm.fieldLock}
          invoiceDate={vm.invoiceDate}
          onInvoiceDateChange={vm.setInvoiceDate}
          invoiceCode={vm.invoiceCode}
          isNew={vm.isNew}
          customerId={vm.customerId}
          customerCode={vm.customerCode}
          customerName={vm.customerName}
          onCustomerSelect={vm.customerHandlers.onSelect}
          onCustomerClear={vm.customerHandlers.onClear}
          taxCode={vm.taxCode}
          onTaxCodeChange={vm.setTaxCode}
          description={vm.description}
          onDescriptionChange={vm.setDescription}
        />
        <div className={[df.section, df.linesSection, vm.fieldLock.viewSectionClass].filter(Boolean).join(' ')}>
          <h2 className={df.sectionTitle}>Chi tiết hàng hóa</h2>
          <InvoiceLinesGrid
            lines={vm.lines}
            canEdit={vm.canEditLines}
            onChange={vm.setLines}
            patchLine={vm.patchLine}
            onAddLine={addLine}
            onCopyLine={copyLine}
            lineRowProps={lineRowProps}
            onRemoveLine={removeLine}
          />
        </div>
      </SalesVoucherFormShell>

      <UnsavedChangesModal
        isOpen={vm.showUnsavedModal}
        onStay={vm.cancelLeave}
        onLeave={vm.confirmLeave}
        data-testid={`${vm.TEST_ID}-unsaved-modal`}
      />

      <AllocationVarianceConfirmModal
        isOpen={vm.showVarianceConfirm}
        varianceAmount={vm.varianceAmount}
        onCancel={() => vm.setShowVarianceConfirm(false)}
        onConfirm={vm.confirmVarianceSave}
        data-testid={`${vm.TEST_ID}-variance-modal`}
      />

      <HeaderDiscountClearConfirmModal
        isOpen={vm.showHeaderDiscountClearConfirm}
        onStay={vm.cancelHeaderDiscountClear}
        onConfirm={vm.confirmHeaderDiscountClear}
        data-testid={`${vm.TEST_ID}-header-discount-clear-modal`}
      />
    </>
  );
};

export default HoaDonFormPage;
